#\n# @lc app=leetcode id=3367 lang=python3\n#\n# [3367] Maximize Sum of Weights after Edge Removals\n#\n\n# @lc code=start\nclass Solution:\n    def maximizeSumOfWeights(self, edges: List[List[int]], k: int) -> int:\n        from collections import defaultdict\n        # Step 1: Sort edges by weight in descending order\n        edges.sort(key=lambda x: x[2], reverse=True)\n        \n        # Step 2: Initialize node degree count\n        degree = defaultdict(int)\n        max_sum = 0\n        for u, v, w in edges:\n            # Check if adding this edge would violate the degree constraint for either node\n            if degree[u] < k and degree[v] < k:\n                # Step 3: Add this edge to our resulting graph\n                max_sum += w\n                degree[u] += 1\n                degree[v] += 1\n        \n        return max_sum\n# @lc code=end